package dev.yae.madokaQueue.game.gamemode;

import org.bukkit.Bukkit;
import org.bukkit.entity.Player;
import org.bukkit.inventory.ItemStack;

import java.util.Base64;

public class MaceGamemode extends Gamemode {
    private static final String KIT = "";

    private static final ItemStack[] CONTENTS = decode(KIT);

    @Override
    public String getName() {
        return "Mace";
    }

    @Override
    public void equipKit(Player player) {
        player.getInventory().setContents(CONTENTS);
    }

    private static ItemStack[] decode(String base64) {
        try {
            return ItemStack.deserializeItemsFromBytes(Base64.getDecoder().decode(base64));
        } catch (RuntimeException exception) {
            return new ItemStack[0];
        }
    }
}
